Preventing GC sweeping on custom object variables:

```cpp
#include

UCLASS()
class UInventoryItem : public UObject {
    GENERATED_BODY()
};

UCLASS()
class APlayerCharacter : public ACharacter {
    GENERATED_BODY()

    // UPROPERTY registration ensures the reference tracking registry knows about this pointer
    UPROPERTY()
    UInventoryItem* EquippedItem;
};
```
